const response = $input.first().json;

if (response.status !== 'OK') {
  return [{ json: { error: 'Maps API error: ' + response.status, travel_fee: 0, zone_label: 'Unknown', miles: null, drive_time_minutes: null } }];
}

const element = response.rows[0].elements[0];

if (element.status !== 'OK') {
  return [{ json: { error: 'Could not calculate distance to this address. Please verify the address and try again.', travel_fee: 0, zone_label: 'Unknown', miles: null, drive_time_minutes: null } }];
}

const miles = element.distance.value / 1609.344;
const driveTimeMinutes = Math.round(element.duration.value / 60);

let zone_label, travel_fee;
if (miles <= 15) {
  zone_label = 'Local (within 15 miles)';
  travel_fee = 0;
} else if (miles <= 30) {
  zone_label = 'Zone 1 (16–30 miles)';
  travel_fee = 25;
} else if (miles <= 60) {
  zone_label = 'Zone 2 (31–60 miles)';
  travel_fee = 60;
} else if (miles <= 100) {
  zone_label = 'Zone 3 (61–100 miles)';
  travel_fee = 110;
} else {
  zone_label = 'Out of Service Area (over 100 miles)';
  travel_fee = -1;
}

return [{ json: {
  miles: Math.round(miles * 10) / 10,
  drive_time_minutes: driveTimeMinutes,
  distance_text: element.distance.text,
  drive_time_text: element.duration.text,
  zone_label,
  travel_fee
} }];
